sp_widget.client_script:
api.controller = function($scope, $timeout, $location, $rootScope, amb, spModal, spUtil, htmlToStringService, dtechTemplateService) {
    //------------------------------------------------------------------------------------------------------------------------
    // COMPANY: DISCOVER TECHNOLOGIES
    // CUSTOMIZED BY: KARINA TORRES
    // RECURSIVE GRAPHICAL TREE FOR PROCESS TEMPLATE
    // HELPUL LINKS: https://gojs.net/latest/intro/textblocks.html
    //------------------------------------------------------------------------------------------------------------------------
    // 2.5.21 | 09.08.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
    // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Add a private function to convert HTML to a simple string
    //											Added missing semicolons, formatted code
    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
    //											some special characters in "instruction" or "Signature Instructions" field
    // 											Remove private function to convert HTML to a simple string; use service instead
    //											Instructions and Signature Instructions need HTML converted to string before
    //											the call to substring with field.maxChars
    //------------------------------------------------------------------------------------------------------------------------

    var c = this;
    var twjs = x_153465_discovert.twJS;
	// STRY0142161
	var drag_drop = x_153465_discovert.DTech_gojs_drag_drop;

    var TREE_CONST;
    var modalObjects;
    var $go; // for conciseness in defining templates
    //  UI/UX - STRY0065140 - 2.5 Template List - FIX
    var diagram;
    // this is used to set the initial select percent
    var diagramInitCompleted = false;

    // overview is the picture-in-picture image of the diagram
    var myOverview;
    var treeOrientation;
    var treeNodeAngle;
    var url_id;
    var watcher;
    // TREE FOOTER TOOLBAR
    var viewPortHeight = 0;

    // DFCT0011119
    init();

    // DFCT0011119 - check to see if the tree is loaded, if not run a late check on URL 
    //               the Template Tab List widget does a set of the sys_id in the URL while loading
    function init() {
        if (c.data.table == "x_153465_discovert_discover_routing_template") {
            var search = $location.search();
            if (c.data.topParentTask_id != search.sys_id) {
                $scope.data.selectedId = search.sys_id;
                $scope.data.table = "x_153465_discovert_discover_routing_template";
                spUtil.update($scope).then(function() {
                    main();
                });
                // prevent calling main until post back with data
                return;
            }
        }
        // call main function
        main();
    }

    function main() {
        TREE_CONST = _loadTreeConstants();
        $go = go.GraphObject.make; // for conciseness in defining templates

        // STRY0040294
        if ((!c.data.selectedId || c.data.selectedId == 'null') && c.data.topParentTask_id) {
            c.data.selectedId = c.data.topParentTask_id;
        }

        // STRY0069986 - move to top
        url_id = $location.search().sys_id;
        // DFCT0010838 needed to look for null string also
        if (!url_id || url_id == 'null') {
            broadcastTopNodeChange(c.data.selectedId);
        }

        // STRY0040294 - use record watcher to keep grid synced
        // RJA 2021.04.14 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
        initRecordWatcher("x_153465_discovert_route_tasks", "tasker_process_definition=" + $scope.data.templateId);

        $scope.page = {
            displayValue: $scope.data.title,
            value: $scope.data.topParentTask_id,
            name: 'page'
        };

        // STRY0069986 - one draw tree function, not 2 places with the same logic.
        if ($scope.data.topParentTask_id) {
            if (c.data.widgetTreeHeaderToolbars) {
                // load orientation from the header widget
                treeOrientation = c.data.widgetTreeHeaderToolbars[0].data.settings.treeOrientation;
            }
            resetDiagram();
        }
    }

    // STRY0117600
    function _loadTreeConstants() {
        var oTREE_CONST = {
            // DFCT0011227
            tree_name_max_length: 43,
            tree_details_max_length: 43,
            // STRY0096157 - TUP - Template Tree Min Size to avoid cutting off tool tip
            fontStyle: "14px Segoe UI",
            fontStyleTaskerNumber: "10px Segoe UI",
            fontStyleNodeDetails: "12px Segoe UI",
            textStrokeColor: "white",
            node_id: "page_map_new",
            minHeight: 435, // DFCT0010887 & DFCT0010911 was 12
            diagramMinHeight: 150,
            horizontalTreeAngle: 0,
            verticalTreeAngle: 90,
            outlineWidth: 2,
            roundedRectangleFill: "Gray",
            node_active_bg: '#33738e',
            node_inactive_bg: '#787878',
            node_selected_border: '#00A4FF',
            node_selected_border_stroke_width: 4,
            nodeOuterRectangelWidth: 310,
            nodeOuterRectangelHeight: 80,
            nodeTextPanelMargin: 5,
            numberPanelWidth: 90,
            textPanelMinWidth: 290,
            textPanelMinHeight: 35,
            textPanelMaxWidth: 290,
            textPanelMaxHeight: 35,

            spacingNode: 5,
            spacingLayer: 60,

            // STRY0109209 - Add Create Icon
            font_awesome_plus_o: '\uf067',
            font_awesome_calendar_o: '\uf073',
            font_awesome_user_o: '\uf007',
            font_awesome_exclamation_triangle_o: '\uf071',
            //font_awesome_pencil_square_o: '\uf044',
            // STRY0124682
            font_awesome_info_o: '\uf129',
            icon_normal_stroke: "white",
            icon_hover_stroke: "#F00",
            icon_warning_stroke: "#FF0",
            icon_font: '18px FontAwesome',
            icon_top_margin: 2,
            icon_right_margin: 5,
            icon_bottom_margin: 2,
            icon_left_margin: 5,
            icon_panel_width: 200,

            toolTipHoverDelay: 700,
            toolTipDuration: 10000,
            toolTipBackgroundColor: '#FFFFFF', // "#C5C5C5"
            tooltipTextColor: '#3A3F51',
            toolTipNormalMargin: 3,
            toolTipWarningNoteMargin: 6,
            toolTipColumnWidth: 600, // "auto",
            toolTipWarningMessageColumnWidth: 600
        };
        return oTREE_CONST;
    }

    function _loadModalObjects() {
        var oModalObjects = {
            runTemplateForm: {
                modalKey: 'runTemplateForm',
                title: 'Template Instance',
                backdrop: 'static',
                widget: 'discovertasker-widget-modal-prompt',
                widgetInput: {
                    // this field is added at runtime with the template id
                    process_template_sys_id: $scope.data.templateId,
                    view: 'Default_View', // NOTE, we may need to look up default
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                size: 'lg',
                buttons: [{
                    label: 'Close',
                    cancel: true
                }]
            },
            templateInformationForm: {
                modalKey: 'templateInformationForm',
                title: 'Template Information',
                backdrop: 'static',
                widget: 'discovertasker-formtab',
                widgetInput: {
                    table: 'x_153465_discovert_discover_routing_template',
                    // this field is added at runtime with the template id
                    sys_id: $scope.data.templateId,
                    isModal: true
                },

                size: 'lg',
                buttons: []
            },
            templateDurationForm: {
                modalKey: 'templateDurationForm',
                title: '', // set at runtime
                message: '',
                backdrop: 'static',
                widget: 'tasker_modal_additional_information',
                widgetInput: {
                    table: 'x_153465_discovert_route_tasks',
                    sys_id: '', // set at runtime
                    view: 'Duration_View',
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: []
            },
            createTaskTemplateForm: {
                modalKey: 'createTaskTemplateForm',
                title: '', // set at runtime
                message: '',
                backdrop: 'static',
                widget: 'discovertasker-formtab',
                widgetInput: {
                    table: 'x_153465_discovert_route_tasks',
                    query: '', // set at runtime
                    sys_id: -1,
                    view: 'Default_View', // NOTE, we may need to look up default
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: []
            },
            operationalForm: {
                modalKey: 'operationalForm',
                title: '', // set at runtime
                message: '',
                backdrop: 'static',
                widget: 'tasker_modal_additional_information',
                widgetInput: {
                    table: 'x_153465_discovert_route_tasks',
                    //STRY0095887
                    sys_id: '', // set at runtime
                    view: 'Operational_View',
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: []
            },
            assignmentForm: {
                modalKey: 'assignmentForm',
                title: '', // set at runtime
                message: '',
                backdrop: 'static',
                widget: 'tasker_modal_additional_information',
                widgetInput: {
                    table: 'x_153465_discovert_route_tasks',
                    //STRY0095887
                    sys_id: '', // set at runtime
                    view: 'Assignment_View',
                    hideRelatedLists: true,
                    omitHeader: 'true',
                    hideAttachmentBtn: true,
                    isModal: true
                },
                shared: {},
                size: 'lg',
                buttons: []
            }
        };

        return oModalObjects;
    }

    // -----------------------------------------------------------------------------------------------------------------
    // START RECORD WATCHER BLOCK
    // -----------------------------------------------------------------------------------------------------------------
    // RJA 2021.04.14 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
    function initRecordWatcher(table, filter) {
        if (watcher)
            watcher.unsubscribe();

        if (table && filter) {
            // STRY0093948 - when a row is removed, broadcast event to Tab Form with Tabs to update the count
            var params = {};
            var watcherChannel = amb.getChannelRW(table, filter);
            amb.connect();
            watcher = watcherChannel.subscribe(function(name) {
                var changes = name.data.changes;
                var sys_id = name.data.sys_id;
                switch (name.data.operation) {
                    case "update":
                        var nodeChangedFound = diagram.model.findNodeDataForKey(sys_id);
                        if (nodeChangedFound) {
                            var nodeDataChanged = false;
                            for (var change in changes) {
                                if (c.data.fieldsInModel[changes[change]]) {
                                    nodeDataChanged = true;
                                    // DFCT0010800
                                    // can't break, need to loop through all changes to check if active top changed
                                    //                                    break;
                                    if (changes[change] == 'active' && !nodeChangedFound.parent) {
                                        // TREE FOOTER TOOLBAR
                                        // STRY0117600 - does not like diagram posted back to server
                                        c.data.widgetTreeFooterToolbars[0].diagram = null;
                                        c.data.widgetTreeHeaderToolbars[0].diagram = null;

                                        // the active flag changed on the top neode, need to reset data.canRunTemplate
                                        // in the future, find a way to just call back to the server to only update that field
                                        // for now, force a redraw
                                        spUtil.update($scope);
                                    }
                                }
                            }

                            if (nodeDataChanged) {
                                updateModelNodeData(nodeChangedFound, name.data.record);
                            }
                        }
                        break;
                    case "insert":
                        if (name.data.record.parent) {
                            var newNodeData = createModelNodeData(sys_id, name.data.record);
                            diagram.startTransaction("Add new Task");
                            diagram.model.addNodeData(newNodeData);
                            // STRY0117609
                            var parentKey = name.data.record.parent.value;
                            diagram.model.setParentKeyForNodeData(newNodeData, parentKey);
                            var parentNodeData = diagram.model.findNodeDataForKey(parentKey);
                            diagram.model.setDataProperty(newNodeData, 'active', parentNodeData.active);
                            diagram.commitTransaction("Add new Task");
                        }
                        break;
                    case "delete":
                        var nodeDeletedFound = diagram.model.findNodeDataForKey(sys_id);
                        if (nodeDeletedFound) {
                            diagram.model.removeNodeData(nodeDeletedFound);
                        }
                }
            });
        }
    }

    function createModelNodeData(sys_id, record) {
        var newNodeData = {};
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to_individual'
                    newNodeData[key] = record[key].value;
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    newNodeData[key] = displayValue;
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_individual_DisplayValue'
                    newNodeData[key + '_DisplayValue'] = displayValue;
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].display_value, g_user_date_time_format);
                    // STRY0091251 - STRETCH-TUP(Estimated Duration Calculation)  - calculate Estimated Duration for Task Template Tree to show where Parent duration is shorter than sum of children
                    // server is loading duration values in UTC
                    var gdt = new Date();
                    // returns the offset in minutes
                    // updates offset to miliseconds
                    date_number = date_number - (gdt.getTimezoneOffset() * 60 * 1000);
                    newNodeData[key] = date_number;
                }
                if (field.type == 'time') {
                    var gdTime = new Date(record[key].value);
                    var time_number = (gdTime.getHours() * 60 + gdTime.getMinutes() * 60 + gdTime.getSeconds()) * 1000;
                }
                if (field.type == 'boolean') {
                    newNodeData[key] = (record[key].value == "true" || record[key].value == true);
                }
            } //if field wasn't found do nothing
        }
        newNodeData.name = getTaskTitleNode(newNodeData);
        // DFCT0011078 - STRY0127737 - updated name and details and separated number
        newNodeData.nodeDetails = getTaskNodeDetails(newNodeData);

        newNodeData.warning = {};
        newNodeData.warning.waitStatewithNoSubtasks = (newNodeData.u_wait_for_subtasks_to_finish == 'true' && (parseInt(newNodeData.calchaschildren) == 0));
        newNodeData.warning.primaryAssigneeEmpty = (newNodeData.primary_assignee == '' || newNodeData.primary_assignee == null);
        // STRY0095897
        newNodeData.warning.taskingAuthorityEmpty = ((newNodeData.tasking_authority == '' || newNodeData.tasking_authority == null));
        newNodeData.warning.primaryOfficeEmpty = ((newNodeData.primary_office == '' || newNodeData.primary_office == null));

        // STRY0110317 calculate the due date to be set using days and Time
        newNodeData.actualTime = 0;
        if (newNodeData.u_duration_days >= 0) {
            newNodeData.actualTime = newNodeData.u_duration_days * 86400000;
        }
        if (newNodeData.u_duration_time_due >= 0) {
            newNodeData.actualTime += newNodeData.u_duration_time_due;
        }

        // if status is not provided on a new record, set to unkown
        if (!newNodeData.status)
            newNodeData.status = 'unkown';

        return newNodeData;
    }
    // load all of the field names used in the task tree nodes (see TaskHelpers.getTaskTreeLevelO and TaskHelpers.getTaskTitleNode)
    function updateModelNodeData(nodeData, record) {
        // STRY0117609
        var activeChanged = false;
        var activeValue;
        for (var key in record) {
            var displayValue = '';
            var fieldLabel = '';
            var field = c.data.fieldsInModel[key];
            if (field) {
                fieldLabel = field.fieldLabel;
                // STRY0117609
                if (field.fieldName == 'active') {
                    activeValue = (record[key].value == "true" || record[key].value == true);
                    if (nodeData[key] != activeValue) {
                        activeChanged = true;
                    }
                }

                // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
                // displayValue = record[key].display_value;
                if ((field.fieldName == 'u_signature_instructions') || (field.fieldName == 'instructions')) {
                    displayValue = htmlToStringService.convertHtmlToString(record[key].display_value);
                } else {
                    displayValue = record[key].display_value;
                }

                if (field.maxChars > 0)
                    displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
                if (field.hasValue) {
                    // many have value, only a few have only value 'calchaschildren', 'parent', 'u_wait_for_subtasks_to_finish'
                    // others 'primary_assignee', 'primary_office', 'tasking_authority', 'state', 'assigned_to_individual'
                    diagram.model.setDataProperty(nodeData, key, record[key].value); // this is the default value to key match
                }
                if (field.keyUsesDisplayOnly) {
                    // 'status', 'task_name', 'u_active_subtasks', 'order', 'u_reviewer': 
                    diagram.model.setDataProperty(nodeData, key, displayValue);
                }
                if (field.hasDiplayValue) {
                    // 'state_DisplayValue', 'assigned_to_individual_DisplayValue'
                    diagram.model.setDataProperty(nodeData, key + '_DisplayValue', displayValue);
                }
                if (field.type == 'date') {
                    var date_number = getDateFromFormat(record[key].display_value, g_user_date_time_format);
                    // STRY0091251 - STRETCH-TUP(Estimated Duration Calculation)  - calculate Estimated Duration for Task Template Tree to show where Parent duration is shorter than sum of children
                    // server is loading duration values in UTC
                    var gdt = new Date();
                    // returns the offset in minutes
                    // updates offset to miliseconds
                    date_number = date_number - (gdt.getTimezoneOffset() * 60 * 1000);
                    diagram.model.setDataProperty(nodeData, key, date_number);
                }
                if (field.type == 'time') {
                    var gdTime = new Date(record[key].value);
                    var time_number = (gdTime.getHours() * 60 + gdTime.getMinutes() * 60 + gdTime.getSeconds()) * 1000;
                    diagram.model.setDataProperty(nodeData, key, time_number);
                }
                if (field.type == 'boolean') {
                    var bValue = (record[key].value == "true" || record[key].value == true);
                    diagram.model.setDataProperty(nodeData, key, bValue);
                }
            } //if field wasn't found do nothing
        }
        // STRY0110317 calculate the due date to be set using days and Time
        var actualTime = 0;
        if (nodeData.u_duration_days >= 0) {
            actualTime = nodeData.u_duration_days * 86400000;
        }
        if (nodeData.u_duration_time_due >= 0) {
            actualTime += nodeData.u_duration_time_due;
        }
        if (nodeData.actualTime != actualTime) {
            diagram.model.setDataProperty(nodeData, 'actualTime', actualTime);
        }

        var nameValue = getTaskTitleNode(nodeData);
        if (nodeData.name != nameValue) {
            diagram.model.setDataProperty(nodeData, 'name', nameValue);
        }

        // DFCT0011078 - STRY0127737 - updated name and details and separated number
        var nodeDetails = getTaskNodeDetails(nodeData);
        if (nodeData.nodeDetails != nodeDetails) {
            diagram.model.setDataProperty(nodeData, 'nodeDetails', nodeDetails);
        }

        var newWaitState = (nodeData.u_wait_for_subtasks_to_finish == 'true' && (parseInt(nodeData.calchaschildren) == 0));
        if (nodeData.warning.waitStatewithNoSubtasks != newWaitState) {
            diagram.model.setDataProperty(nodeData.warning, 'waitStatewithNoSubtasks', newWaitState);
        }

        var primaryAssigneeEmpty = (nodeData.primary_assignee == '' || nodeData.primary_assignee == null);
        if (primaryAssigneeEmpty != nodeData.warning.primaryAssigneeEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'primaryAssigneeEmpty', primaryAssigneeEmpty);
        }
        // STRY0095897
        var taskingAuthorityEmpty = ((nodeData.tasking_authority == '' || nodeData.tasking_authority == null));
        if (taskingAuthorityEmpty != nodeData.warning.taskingAuthorityEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'taskingAuthorityEmpty', taskingAuthorityEmpty);
        }
        // STRY0095897
        var primaryOfficeEmpty = ((nodeData.primary_office == '' || nodeData.primary_office == null));
        if (primaryOfficeEmpty != nodeData.warning.primaryOfficeEmpty) {
            diagram.model.setDataProperty(nodeData.warning, 'primaryOfficeEmpty', primaryOfficeEmpty);
        }

        // STRY0117609
        if (activeChanged) {
            // update all subtasks 
            updateActiveChildren(nodeData.sys_id, activeValue);
        }


        diagram.model.updateTargetBindings(nodeData);
    }

    function getTaskTitleNode(nodeData) {
        var nodeTitle = nodeData.short_description;
        if (nodeData.route_order != null && nodeData.route_order != 0)
            nodeTitle = nodeData.route_order + ". " + nodeTitle;
        // DFCT0011078 - STRY0127737 - updated name and details and separated number
        if (nodeTitle.length > TREE_CONST.tree_name_max_length) {
            nodeTitle = nodeTitle.substring(0, TREE_CONST.tree_name_max_length) + "...";
        }
        return nodeTitle;
    }

    // DFCT0011078 - STRY0127737 - updated name and details and separated number
    function getTaskNodeDetails(nodeData) {
        // DFCT0011078
        var nodeDetails = "";
        nodeDetails = '(' + nodeData.primary_assignee_DisplayValue + ')';
        // DFCT0011227
        if (nodeDetails.length > TREE_CONST.tree_details_max_length) {
            nodeDetails = nodeDetails.substring(0, TREE_CONST.tree_details_max_length) + "...";
        }
        return nodeDetails;
    }

    // STRY0117609
    function updateActiveChildren(parentKey, newActiveValue) {
        var parentNode = diagram.findNodeForKey(parentKey);
        var parentNodeData = diagram.model.findNodeDataForKey(parentKey);

        var inactiveDueToParent = false;
        if (parentNodeData)
            inactiveDueToParent = parentNodeData.inActiveDueToParent || !parentNodeData.active;

        var childrenNodes = parentNode.findTreeChildrenNodes();
        while (childrenNodes.next()) {
            var childNode = childrenNodes.value;
            var setActive = newActiveValue;
            if (inactiveDueToParent) {
                setActive = false;
                if (!childNode.data.inActiveDueToParent && !childNode.data.active) {
                    diagram.model.setDataProperty(childNode.data, 'inActiveDueToParent', false);
                } else {
                    diagram.model.setDataProperty(childNode.data, 'inActiveDueToParent', true);
                }
            } else {
                // if the child was inactive due to parent
                if (childNode.data.inActiveDueToParent && parentNodeData.active) {
                    setActive = true;
                } else {
                    setActive = childNode.data.active;
                }
                diagram.model.setDataProperty(childNode.data, 'inActiveDueToParent', false);
            }
            diagram.model.setDataProperty(childNode.data, 'active', setActive);
            diagram.model.updateTargetBindings(childNode.data);
            updateActiveChildren(childNode.data.sys_id, newActiveValue);
        }
    }
    // -----------------------------------------------------------------------------------------------------------------
    // END RECORD WATCHER BLOCK
    // -----------------------------------------------------------------------------------------------------------------

    // -----------------------------------------------------------------------------------------------------------------
    // START EVENTS RAISED
    // -----------------------------------------------------------------------------------------------------------------
    function broadcastTopNodeChange(topId) {
        var evt = {};
        evt.sys_id = topId;
        evt.table = c.data.table_detail;
        evt.parent = '';
        $rootScope.$broadcast('$sp.list.click', evt);
    }

    function nodeSelectionChanged(node) {

        var evt = {};
        var d = node.data;
        evt.sys_id = d.sys_id;

        if (evt.sys_id == c.data.selectedId) { // get called twice by gojs
            return;
        }
        // STRY0093948 = template was not loading the form on changing node selection
        evt.table = c.data.table_detail;
        // RJ -ET - Story 4
        evt.parent = d.parent;

        c.data.selectedId = evt.sys_id;
        // TREE FOOTER TOOLBAR
        // STRY0117600 - need to update the child widget toolbar footer
        // this sets the selected id on the footer tooltip when the selected id changes
        c.data.widgetTreeFooterToolbars[0].parentSelectedId = c.data.selectedId;
        c.data.widgetTreeHeaderToolbars[0].parentSelectedId = c.data.selectedId;

        $location.search('table', evt.table).search('sys_id', evt.sys_id).search('spa', 1);
        $rootScope.$broadcast('$sp.list.click', evt);

        diagram.centerRect(node.actualBounds);
    }
    // -----------------------------------------------------------------------------------------------------------------
    // END EVENTS RAISED
    // -----------------------------------------------------------------------------------------------------------------

    // -----------------------------------------------------------------------------------------------------------------
    // START EVENTS MONITORED
    // -----------------------------------------------------------------------------------------------------------------
