		function _changeTemplate(objTemplate){
			// TREE FOOTER TOOLBAR
			// STRY0117600 - does not like diagram posted back to server
			c.data.widgetTreeFooterToolbars[0].diagram = null;
			c.data.widgetTreeHeaderToolbars[0].diagram = null;

			$scope.data.selectedId = objTemplate.sys_id;
			$scope.data.table = "x_153465_discovert_discover_routing_template"; //item.table;//"x_153465_discovert_route_tasks";


			//  UI/UX - STRY0065140 - 2.5 Template List - FIX
			if (objTemplate.template_level_display_value) c.data.process_level = objTemplate.template_level_display_value;
			if (objTemplate.template_name) c.data.name = objTemplate.template_name;

			//$location.search('table', $scope.data.table).search('sys_id', $scope.data.selectedId).search('spa', 1);
			spUtil.update($scope).then(function() {
				// RJA 2021.04.14 - TUP - Filter was not working for OU Templates in Template LIst screen - issue introduced in 2.6
				initRecordWatcher("x_153465_discovert_route_tasks", "tasker_process_definition=" + $scope.data.templateId);
				// STRY0121782 - settings changed, force reload of the settings
				if (c.data.widgetTreeHeaderToolbars) {
					// load orientation from the header widget
					treeOrientation = c.data.widgetTreeHeaderToolbars[0].data.settings.treeOrientation;
				}
				resetDiagram();
				// STRY0123864 - changing the selected template updates the URL
				$location.search('table', $scope.data.table).search('sys_id', objTemplate.sys_id).search('spa', 1);
			});	
		}
