    $scope.openModalCloneTemplate = function() {
			var newTemplateName = $scope.data.templateInfo.template_name;
			_promptForTemplateNameAndClone(newTemplateName, true);
    };

		function _cloneTemplate(templateInfo){
			// set the new template owner for the cloned template
			templateInfo.new_template_owner = $scope.data.currentUserId;
			dtechTemplateService.cloneTemplate(templateInfo).then(
						function(response){
							var cloneSuccess = true;
							if(response && response.success){
								// need new top task here an push back to server to reload
								if(response.new_topTask_id  && response.new_topTask_id != ''){
									// change selected id
									$scope.data.selectedId = response.new_topTask_id;
									// reload with cloned template
									spUtil.update($scope);
									var objTemplate = {};
									objTemplate.sys_id = response.template_id;
									objTemplate.template_level_display_value = response.template_level_display_value;
									objTemplate.template_name = response.template_name;
									_changeTemplate(objTemplate);									
								}
							}
							if(!cloneSuccess){
								// TODO Multilingual
								spModal.alert("Clone did not return proper redirect information.  There may have been a problem cloning the template");
							}
					});
		}

		// this function prompts for template name and stays in loop until canceled or unique name is entered
		function _promptForTemplateNameAndClone(name, initialPrompt){
			// prompt for name until unique
			var templateInfo= $scope.data.templateInfo;
			// set the current user as the template owner
			templateInfo.template_owner = $scope.data.currentUserId;
			templateInfo.template_name = name;
// TODO - MULTILINGUAL
			var cloneNamePrompt = "Enter name for cloned Template";
			if(!initialPrompt){
				cloneNamePrompt = "Name entered is not unique. " + cloneNamePrompt;
			}
			spModal.prompt(cloneNamePrompt, name).then(
				function(nameEntered){
					templateInfo.new_template_name = nameEntered;
					dtechTemplateService.isTemplateNameUnique(templateInfo).then(
						function(response){
							if(response && response.success){
								if(response.isTemplateNameUnique){
									_cloneTemplate(templateInfo);
								} else {
									// prompt user to try again
									_promptForTemplateNameAndClone(nameEntered, false);
								}
							}
					});
				});
		}

