    // Define a simple node template consisting of text followed by an expand/collapse button
    function _createNodeTemplate() {
        var nodeTemplate = $go(go.Node, treeOrientation, {
                selectionAdorned: false,
                selectionChanged: nodeSelectionChanged,
                isTreeExpanded: true,
                isTreeLeaf: true
            }, // this event handler is defined below

            _createTreeNode(),
            $go("TreeExpanderButton") // this was overkill for small diagrams
        );
        return nodeTemplate;

    }

    function _createNumberHeader() {
        var numberHeader =
            $go(go.TextBlock, {
                    alignment: go.Spot.Left,
                    width: TREE_CONST.numberPanelWidth,
                    stroke: TREE_CONST.textStrokeColor,
                    font: TREE_CONST.fontStyleTaskerNumber
                },
                new go.Binding("text", "", function(data) {
                    return data.number;
                })
            );
        return numberHeader;
    }

    function _createIcon(iconName, iconText) {
        var icon = $go(go.TextBlock, {
                name: iconName,
                text: iconText,
                margin: new go.Margin(TREE_CONST.icon_top_margin, TREE_CONST.icon_right_margin, TREE_CONST.icon_bottom_margin, TREE_CONST.icon_left_margin),
                alignment: go.Spot.Right,
                font: TREE_CONST.icon_font,
                editable: false,
                isMultiline: false,
                isActionable: true,
                click: function(e, obj) {
                    openIconForm(obj, iconName);
                    e.handled = true;
                },
                mouseEnter: function(e, obj) {
                    obj.saveStroke = obj.stroke;
                    obj.stroke = TREE_CONST.icon_hover_stroke;
                },
                mouseLeave: function(e, obj) {
                    obj.stroke = obj.saveStroke;
                    obj.saveStroke = null;
                }
            },
            new go.Binding("toolTip", "", function(nodeData) {
                return toolTipJSON(iconName, nodeData);
            }),
            new go.Binding("text", "", function(data) {
                if (iconName == 'ExclamationIcon') {
                    if (data.u_warning_projected_due_date_before_child || data.u_warning_projected_due_date_after_parent || data.warning.waitStatewithNoSubtasks || data.warning.primaryAssigneeEmpty || data.warning.taskingAuthorityEmpty || data.warning.primaryOfficeEmpty)
                        return TREE_CONST.font_awesome_exclamation_triangle_o;
                    else
                        return '';
                } else {
                    return iconText;
                }
            }),
            //this binds the stroke color to the level property of the data mapping, the function uses the level to determine the color
            //the fake logic sets the warning color, otherwise use the default color.
            new go.Binding("stroke", "", function(data) {
                var iconStroke = TREE_CONST.icon_normal_stroke;
                switch (iconName) {
                    case 'UserIcon':
                        // STRY0095897
                        if (data.warning.primaryAssigneeEmpty || data.warning.taskingAuthorityEmpty || data.warning.primaryOfficeEmpty)
                            iconStroke = TREE_CONST.icon_warning_stroke;
                        break;
                    case 'DurationIcon':
                        if (data.u_warning_projected_due_date_before_child || data.u_warning_projected_due_date_after_parent || data.warning.waitStatewithNoSubtasks)
                            iconStroke = TREE_CONST.icon_warning_stroke;
                        break;
                    case 'ExclamationIcon':
                        iconStroke = TREE_CONST.icon_warning_stroke;
                        break;
                }
                return iconStroke;
            }),
            new go.Binding("visible", "canCreate")
        );

        return icon;
    }

    function _createIconPanel() {
        var iconPanel =
            $go(go.Panel, "Horizontal", {
                    alignment: go.Spot.Right,
                    width: TREE_CONST.icon_panel_width,
                    isOpposite: true
                },
                // STRY0109209 - Add Create Icon
                _createIcon('AddIcon', TREE_CONST.font_awesome_plus_o),
                _createIcon('DurationIcon', TREE_CONST.font_awesome_calendar_o),
                _createIcon('UserIcon', TREE_CONST.font_awesome_user_o),
                // STRY0124682
                _createIcon('OperationalIcon', TREE_CONST.font_awesome_info_o),
                //this binds the exclamation icon to the duration warning  property of the data mapping, 
                //the function uses the level determine if the icon is added or not
                _createIcon('ExclamationIcon', TREE_CONST.icon_warning_stroke)
            );
        return iconPanel;
    }

    function _createVerticalMainPanel() {
        var mainPanel =
            $go(go.Panel, "Auto",
                $go(go.Panel, "Vertical",
                    // DFCT0011134 - STRY0127737 - change name and number display
                    $go(go.Panel, "Horizontal",

                        _createNumberHeader(),
                        _createIconPanel()
                    ),
                    // DFCT0010761 =- changed the height to 35, marin to margin: new go.Margin(0, 5, 0, 5),
                    $go(go.Panel, "Vertical", {
                            alignment: go.Spot.Left,
                            margin: TREE_CONST.nodeTextPanelMargin,
                            minSize: new go.Size(TREE_CONST.textPanelMinWidth, TREE_CONST.textPanelMinHeight),
                            maxSize: new go.Size(TREE_CONST.textPanelMaxWidth, TREE_CONST.textPanelMaxHeight)
                        },
                        $go(go.TextBlock, {
                                alignment: go.Spot.Left,
                                text: "verticalAlignment: Center",
                                textAlign: "left",
                                wrap: go.TextBlock.WrapFit,
                                font: TREE_CONST.fontStyle,
                                stroke: TREE_CONST.textStrokeColor
                            },
                            new go.Binding("text", "name")
                        ),
                        $go(go.TextBlock, {
                                alignment: go.Spot.Left,
                                text: "verticalAlignment: Center",
                                textAlign: "left",
                                wrap: go.TextBlock.WrapFit,
                                font: TREE_CONST.fontStyleNodeDetails,
                                stroke: TREE_CONST.textStrokeColor
                            },
                            new go.Binding("text", "nodeDetails")
                        )
                    )
                )
            );

        return mainPanel;
    }

    function _createTreeNode() {
        var treeNode =
            $go(go.Panel, "Auto",
                _createOurterRoundedRectangle(),
                _createVerticalMainPanel()
            );

        return treeNode;
    }

    function _createOurterRoundedRectangle() {
        // STRY0113936, STRY0111888 - set width and height
        var roundedRectangle =
            $go(go.Shape, "RoundedRectangle", {
                    // STRY0142161
                    mouseDragEnter: function(e, obj) { drag_drop.mouseDragEnter(e, obj);},
                    mouseDrop: function(e, obj) { drag_drop.mouseDrop(e, obj);},
                    mouseDragLeave: function(e, obj) {drag_drop.mouseDragLeave(e, obj);},

                    strokeWidth: TREE_CONST.outlineWidth,
                    width: TREE_CONST.nodeOuterRectangelWidth,
                    height: TREE_CONST.nodeOuterRectangelHeight,
                    fill: TREE_CONST.roundedRectangleFill
                },

                new go.Binding("stroke", "isSelected", function(s) {
                    if (s)
                        return TREE_CONST.node_selected_border;
                    else
                        return null;
                }).ofObject(""),

                new go.Binding("fill", "active", function(t) {
                    switch (t) {
                        case false:
                            return TREE_CONST.node_inactive_bg;
                        case 'false':
                            return TREE_CONST.node_inactive_bg;
                        default:
                            return TREE_CONST.node_active_bg;
                    }
                })
            );

        return roundedRectangle;
    }
