    function _createTableColumn(visibleFlag, rowNum, columnNum, spanMultipleInt, columnWidth, margin, textAlignment, text) {
        var tableColumn;
        tableColumn =
            $go(go.TextBlock, {
                    visible: visibleFlag,
                    row: rowNum,
                    column: columnNum,
                    columnSpan: spanMultipleInt,
                    width: columnWidth,
                    margin: margin,
                    alignment: textAlignment,
                    wrap: go.TextBlock.WrapFit,
                    background: TREE_CONST.toolTipBackgroundColor
                },
                text
            );
        return tableColumn;

    }

    // STRY0091260
    function getToolTipText(objectName, nodeData) {

        var toolTip;
        switch (objectName) {
            // // STRY0109209 - Add Create Icon
            case 'AddIcon':
                toolTip = $go(go.Panel, "Table",
                    // Row 1
                    _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, c.data.messages["Tasker - Add a Subtask"])
                );
                break;
            case 'DurationIcon':
                var durrationWarningCount = 1;
                var warningDays = parseInt(nodeData.warning_hours_DisplayValue);
                var warningDaysText = '';
                if (warningDays > 0) {
                    warningDaysText = c.data.messages["Warning Caption"].replace('{0}', nodeData.warning_hours_DisplayValue).replace('{1}', c.data.dateLabel);
                } else {
                    warningDaysText = c.data.messages['Warning Not Set Caption'];
                }
                var waitStatewithNoSubtasks = (nodeData.warning.waitStatewithNoSubtasks == true);
                var u_warning_projected_due_date_before_child = (nodeData.u_warning_projected_due_date_before_child);
                var u_warning_projected_due_date_after_parent = (nodeData.u_warning_projected_due_date_after_parent);
                toolTip = $go(go.Panel, "Table",
                    // STRY0113121
                    // Row 1
                    _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.u_duration_days.fieldLabel + ": "),
                    _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.u_duration_days_DisplayValue),
                    // Row 2
                    _createTableColumn(true, 1, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.messages["Time Due Caption"].replace('{0}', c.data.fieldsInModel.u_duration_time_due.fieldLabel) + ": "),
                    _createTableColumn(true, 1, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.u_duration_time_due_DisplayValue),
                    // Row 3
                    _createTableColumn(true, 2, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.warning_hours.fieldLabel + ": "),
                    _createTableColumn(true, 2, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, warningDaysText),
                    // Row 4
                    _createTableColumn(true, 3, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.duration.fieldLabel + ": "),
                    _createTableColumn(true, 3, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.duration_DisplayValue),
                    // Row 5 - only shown if duration not set
                    _createTableColumn(waitStatewithNoSubtasks, 4, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker - Warning: Wait state set with no subtasks"]),
                    // Row 5 - only shown if duration not set- // STRY0091251
                    _createTableColumn(u_warning_projected_due_date_before_child, 5, 0, 2, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Warning Parent Before Last Subtask"].replace('{0}', c.data.dateLabel).replace('{1}', c.data.dateLabel)),
                    // Row 6 - only shown if duration not set
                    _createTableColumn(u_warning_projected_due_date_after_parent, 6, 0, 2, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Warning Parent Before this Task"].replace('{0}', c.data.dateLabel).replace('{1}', c.data.dateLabel))
                );
                break;
            case 'OperationalIcon':
                var hasClassification = (nodeData.classification_DisplayValue != 'null');
                var hasSignatureInstructions = (nodeData.u_signature_instructions != 'null');
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1 - DFCT0011078 - STRY0127737 - added name to the table to enable seeing the full longer name
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.short_description.fieldLabel + ": "),
                        _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.short_description),

                        // Row 2
                        _createTableColumn(true, 1, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.tasker_type.fieldLabel + ": "),
                        _createTableColumn(true, 1, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.tasker_type_DisplayValue),
                        // Row 3
                        _createTableColumn(hasClassification, 2, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.classification.fieldLabel + ": "),
                        _createTableColumn(hasClassification, 2, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.classification_DisplayValue),
                        // Row 4
                        _createTableColumn(true, 3, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.u_priority.fieldLabel + ": "),
                        _createTableColumn(true, 3, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.u_priority_DisplayValue),
                        // Row 5
                        _createTableColumn(true, 4, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.u_risk_flag.fieldLabel + ": "),
                        _createTableColumn(true, 4, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.u_risk_flag_DisplayValue),
                        // Row 6
                        _createTableColumn(true, 5, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.instructions.fieldLabel + ": "),
                        // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes"
                        // strip HTML Tags
                        // new go.Binding("text", "", function(data) {
                        //    return data.instructions.replace(/<\/?[^>]+(>|$)/g, "");
                        // convert HTML to a simple string
                        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
                        // return _convertHtmlToSimpleString(data.instructions); // function was removed
                        // Need to call below to have <, >, and & show as that character and not an ALT code
                        _createTableColumn(true, 5, 1, 1, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, htmlToStringService.convertHtmlToString(nodeData.instructions)),
                        // Row 7
                        _createTableColumn(hasSignatureInstructions, 6, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.u_signature_instructions.fieldLabel + ": "),
                        // 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes"
                        // strip HTML Tags
                        // new go.Binding("text", "", function(data) {
                        //    return data.u_signature_instructions.replace(/<\/?[^>]+(>|$)/g, "");
                        // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
                        // return _convertHtmlToSimpleString(data.u_signature_instructions); // function was removed
                        // Need to call below to have <, >, and & show as that character and not an ALT code
                        _createTableColumn(hasSignatureInstructions, 6, 1, 1, TREE_CONST.toolTipWarningMessageColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, htmlToStringService.convertHtmlToString(nodeData.u_signature_instructions))
                    );
                break;
            case 'UserIcon':
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(true, 0, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.tasking_authority.fieldLabel + ": "),
                        _createTableColumn(true, 0, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.tasking_authority_DisplayValue),
                        // Row 2
                        _createTableColumn(true, 1, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.primary_office.fieldLabel + ": "),
                        _createTableColumn(true, 1, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.primary_office_DisplayValue),
                        // Row 3
                        _createTableColumn(true, 2, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.primary_assignee.fieldLabel + ": "),
                        _createTableColumn(true, 2, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.primary_assignee_DisplayValue),
                        // Row 4
                        _createTableColumn(true, 3, 0, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Right, c.data.fieldsInModel.assigned_to_individual.fieldLabel + ": "),
                        _createTableColumn(true, 3, 1, 1, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipNormalMargin, go.Spot.Left, nodeData.assigned_to_individual_DisplayValue)
                    );
                break;
            case 'ExclamationIcon':
                var durationExclamation = (nodeData.u_warning_projected_due_date_before_child || nodeData.u_warning_projected_due_date_after_parent || nodeData.warning.waitStatewithNoSubtasks);
                var assignmentExclamation = (nodeData.warning.primaryAssigneeEmpty || nodeData.warning.taskingAuthorityEmpty || nodeData.warning.primaryOfficeEmpty);
                toolTip =
                    $go(go.Panel, "Table",
                        // Row 1
                        _createTableColumn(durationExclamation, 1, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Duration Warning"]),
                        // row 3
                        _createTableColumn(assignmentExclamation, 3, 0, 2, TREE_CONST.toolTipColumnWidth, TREE_CONST.toolTipWarningNoteMargin, go.Spot.Left, c.data.messages["Tasker -  Warning Assignment"])
                    );
                break;
        }
        return toolTip;
    }

    function toolTipJSON(objectName, nodeData) {
        var toolJSON = $go(go.Adornment, "Spot", "Auto",
            $go(go.Shape, "Rectangle", {
                fill: TREE_CONST.toolTipBackgroundColor
            }),
            getToolTipText(objectName, nodeData)
        );
        return toolJSON;
    }
    // -----------------------------------------------------------------------------------------------------------------
    // END TOOLTIPS
    // -----------------------------------------------------------------------------------------------------------------

};

