sp_widget.description:
2.7 Added Angular Provider htmlToStringService;
Server script updated to use TaskWidgetData instead of TemplateWidgetData;
Client controller, deleted _convertHtmlToSimpleString() which was added on 2021-06-25;

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES & BRIAN KEENER
// GRAPHICAL TREE FOR PROCESS DEFINITION
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 2021-06-25 | mmcc | STRY0102408 "Task Tree Manager" tool tip displays "Unicode Decimal Codes" when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//                                          Changes in Client controller
// 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering 
//											some special characters in "instruction" or "Signature Instructions" field
//											 Instruction or Signature Instructions need to convert HTML to string;
//											 Combine Template Widget Data into Task Widget Data
//                                          Changes in Server script and Client controller
// 2.7.0 | 2021-07-21 | raj | STRY0101803 - Allow for a page just for Scheduled Tasks
//                                          Changes in Server script, HTML
// 2.7.0 | 2021-08-27 | mmcc | STRY0107400 - Draft Scheduled Tasks – UI – Publish from Subtasks
//                                         In HTML, removed unused <div id="infoBoxHolder">
//                                         In CSS, Removed unused #infoBoxHolder selector
//                                         Changes made in HTML and CSS 
// 2.7.0 | 2021-09-03 | raj   | STRY0109209 - Add Create Icon
//																					Changes in Server Script and Client Script
// 2.7.0 | 2021-11-17 | raj  | DFCT0010654 - Spelling Mistake: The "Add a Subtask" plus '+' icon in the Task/Template Information section displays the incorrect tooltip
//                                         Changes made in Server Script
// 2.7.0 | 2021-11-18 | raj  | STRY0114416 - 4 - 2.7 Certification Fixes
//                                         Changes made in Server Script
// 2.7.1 | 2021-12-17 | mmcc | DFCT0010385 - Existing Template Schedules always display the sysID on the Schedule Name field
//                                         In Controller script, Added footer style display none to sp modal open
//                                         Changes made in Controller script 
// 2.7.1 | 2021-12-21 | raj  | DFCT0010725 - "Days for Completion for Completion" on hover of "Template Task" duration icon
//                                         Changes made in Server Script only
// 2.7.2 | 2022-02-04 | raj  | STRY0117609 - Stretch- "Delete" button should be available on the Portal for "Template Tasks"
//                                         - Changes in client script
// 2.7.2 - 2022-02-15 - raj -  DFCT0010800 - "Run Template" button is available on the "Template modal" when "Template" is INACTIVE
//                                         - Changes in client script
// 2.8   - 2022-04-05 - raj -  STRY0117600 - Update Templates to match the UI of Org Hierarchy 
//                                         - Changes in Server Script, client controller, HTML, UI Script and Template
// 2.8   - 2022-04-18 - raj -  STRY0117945 - Org Hierarchy – Preset Zoom Dropdown- Custom Zoom will display in dropdown
//                                         - Changes in Client Controller
// 2.8   - 2022-04-20 - raj -  STRY0120908 - As any Tasker User, if "Org Hierarchy Fullscreen" is accessible from the "Layout Dropdown", I do NOT want it accessible anywhere else.
//                                         - Changes in HTML and ServerScript
// 2.8   - 2022-04-20 - raj -  STRY0120909- Org Hierarchy Fullscreen- Revamp as a Page Layout
//                                         - Changes in HTML and ServerScript
// 2.8   - 2022-04-20 - raj -  STRY0119818 - Task Tree Widget- New Buttons modify Zoom/Structure preferences
//                                           NOTE: also reorganized Template and OU to put all of the repeated functions in the same block of code
//                                         - Changes in Client Controller
// 2.8 | 2022-05-13 | mmcc | DFCT0010887 - New button is gone from Template List page
// 2.8 | 2022-05-13 | mmcc | DFCT0010911 - Templates modal  forms are NOT displaying at ALL
//                                      In HTML, CSS class page_map_wrapper changed to page-map-wrapper;
//                                      CSS class page_map_new changed to page-map
//                                      In Client Controller, set const minHeight: 435; let window on resize use this value; let map_page_Height use it
//                                      Changes made in HTML and Client Controller
// 2.8   - 2022-04-20 - raj -  STRY0123864 - Template- Using 'Layout Navigator' will remember what Template Record the user was on
//                                         - Changes in Client Controller
// 2.8 | 2022-06-17 | mmcc | DFCT0010888 - Zoom buttons are Not always correctly displayed on the Template List page
//                                      In HTML, updated panel panel-default to stick at the top and flex column, 
//                                        updated panel-heading to have a height of 75px, updated div for GoJS to use class flexbox,
//                                        updated div for ng-show="data.topParentTask_id to use class flex cloumn and grow, updated div for page-map-wrapper
//                                        to use class flex cloumn and grow, updated wrapper div to use class flex cloumn and grow,
//                                        updated page-map div to use class flex cloumn and grow.
//                                      Changes made in HTML
// 2.8 | 2022-06-21 | mmcc | STRY0120761 - Template Tree Widget- Add Header and Footer area
//                                      In HTML, deleted div for page-map-wrapper.
//                                      In CSS, deleted some selectors. 
//                                      In Client controller, function resizeDiagram() had all commented out code deleted and
//                                        not calculating height since using Flexbox
//                                      Changes made in HTML, CSS and Client controller
// 2.8   - 2022-07-04 - raj -  STRY0124682 - Task Tree Widget- "Information Icon" matches the Task Form "Information Icon" - NOTE also updated Template Tree
//                                         - Changes in Client Controller
// 2.8   - 2022-07-11 - raj -  STRY0121782 - Stretch- Template Task Tree Widget UX- Update user's "tree-view" preferences
//                                         - Changes in ServerScript only
// 2.8   - 2022-07-15 - raj -  STRY0125255 - Template Layout- Add "Template List Page" as an option
// 2.8   - 2022-07-15 - raj -  STRY0123997 - Templates- System will remember Template Record when switching from any Template Page to the Template List
// 2.8   - 2022-07-29 - raj -  DFCT0011119 - Top Template Record in the list view is NOT selected upon initial page load of the "Template page"
//                                         - Changes in Client Controller
// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer
//                                      In HTML, use new CSS selector dtech-panel-heading-min-height-standard.
//                                      Changes made in HTML.
//
// 2.8 | 2022-08-03 | raj | DFCT0011130 - On the Template updating any fields on the "General Information" modal should NOT update all the Template fields
//                                         - Changes in Client Controller
//  2.8   - 2022-08-16 - raj - DFCT0011078 - Long Task name should NOT impact the  "Task Name", "state" and  "user" name in the Task Tree View
//  2.8   - 2022-08-16 - raj - STRY0127737 - Task Tree/Template Task Tree- New Design for Overflow Text 
//																						Changes in Client Controller
// 2.8   - 2022-08-23 - raj - DFCT0011227 -  Long Task name should NOT impact the  "Task Name", "state" and  "user" name in any "State"
//																			Changes made in Client Controller
// 2.8 | 2022-09-19 | mmcc | STRY0129140 - Task/Template Tree- Add "TaskFlow (tm)"
//                                      In HTML, added 2 div's relative and absolute to position TaskFlowTM_Logo.svg
//                                      Changes made in HTML.
// 2.8.3 (Template Updates Addon)  STRY0142161 - Feature allowing for Templates to be copied/cloned
//										Changes in Server Script, Client Script, and HTML
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {

    main();

    function main() {
        var taskWidgetIconsAndMessage = new TaskerWidgetIconsAndMessages('discovertasker-processtemplatetreegraph');
        var given_sys_id = '';
        // INPUT GOES HERE
        data.settings = taskWidgetIconsAndMessage.loadDefaultsAndSettings($sp);
        data.messages = taskWidgetIconsAndMessage.loadMessages();
        data.icons = taskWidgetIconsAndMessage.loadIcons();

        //----------------------------------------------------------------------------------------------------
        // Initializing Variables
        //----------------------------------------------------------------------------------------------------		
        data.table_detail = "x_153465_discovert_route_tasks";

        data.view = $sp.getParameter("view");
        data.filter = $sp.getParameter("filter");
        data.isValid = true;

        data.templateId = "return none until set";

        // check for input
        if (input) {
            data.table = input.table;
            given_sys_id = input.selectedId;
        } else {
            // input not passed, load based on URL
            given_sys_id = $sp.getParameter("sys_id");
            data.table = $sp.getParameter("table");
        }

        // moved seeting of the selectedid into getting of template
        _loadTemplate(given_sys_id, data.table);
        // STRY0121782 - load after template is loaded
        _loadToolBars();
    }

    function _loadToolBars() {
        // TREE HEADER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        // STRY0120908 - added show separator
        var header_widget_parameters = {
            baseWidget: 'discovertasker-processtemplatetreegraph',
            // STRY0121782
            topId: data.topParentTask_id,
            showSeparator: true,
            iconGroup: 'header'
        };
        data.widgetTreeHeaderToolbars = [];
        data.widgetTreeHeaderToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', header_widget_parameters));

        // TREE FOOTER TOOLBAR
        // STRY0117600 - move toolbar into separate widget to use same functionality across all
        var footer_widget_parameters = {
            baseWidget: 'discovertasker-processtemplatetreegraph',
            // STRY0121782
            topId: data.topParentTask_id,
            iconGroup: 'footer'
        };
        data.widgetTreeFooterToolbars = [];
        data.widgetTreeFooterToolbars.push($sp.getWidget('tasker-tree-toolbar-icons', footer_widget_parameters));
    }

    function _loadTemplate(sys_id, table) {
        var topParentTask_id = _getTopParentTask(sys_id, table);
        if (!topParentTask_id) {
            data.topParentTask_id = undefined;
            return;
        } else {
            data.topParentTask_id = topParentTask_id;
        }

        _loadTemplateMap(data.topParentTask_id);
        // STRY0142161
        // usees data.templateId that is set in the _loadTemplateMap function
        _loadTemplateInfo();
    }

    //------------------------------------------------------------------------------------------------------------------------
    // GET THE TOP PARENT FOR THE CURRENT SYS_ID
    //------------------------------------------------------------------------------------------------------------------------
    function _getTopParentTask(sys_id, table) {
        var topParentTask_id = "";
        var currentRecord = new GlideRecordSecure(table);
        var grTemplate;

        if (currentRecord.get(sys_id)) {
            // STRY0101803 - Allow for a page just for Scheduled Tasks
            switch (table) {
                case 'x_153465_discovert_route_tasks':
                    // Make sure you have top task def by getting the Template and setting the ID to the parent_task_def
                    grTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
                    if (grTemplate.get(currentRecord.tasker_process_definition)) {
                        topParentTask_id = grTemplate.getValue('parent_task_def');
                        // if template task given set the selected id to id provided for lookup
                        data.selectedId = sys_id;
                    }
                    break;
                case 'x_153465_discovert_discover_routing_template':
                    topParentTask_id = currentRecord.getValue('parent_task_def');
                    // if template given set the selected id to the top template task id
                    data.selectedId = topParentTask_id;
                    break;
                case 'x_153465_discovert_tasker_schedule':
                    // Make sure you have top task def by getting the Template and setting the ID to the parent_task_def
                    grTemplate = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
                    if (grTemplate.get(currentRecord.tasker_process)) {
                        topParentTask_id = grTemplate.getValue('parent_task_def');
                        // if schedule given set the selected id to the top template task id
                        data.selectedId = topParentTask_id;

                    }
            }
        }
        return topParentTask_id;
    }
    //------------------------------------------------------------------------------------------------------------------------
  	// STRY0142161
    function _loadTemplateInfo() {
      var gr_Template = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
      if(gr_Template.get(data.templateId)){
        data.templateInfo = {};
        data.templateInfo.template_id = gr_Template.getUniqueValue();
        data.templateInfo.template_name = gr_Template.getValue("template_name");
        data.templateInfo.template_level = gr_Template.getValue("process_level");
        data.templateInfo.template_level_display_value = gr_Template.getDisplayValue("process_level");
        data.templateInfo.template_ou = gr_Template.getValue("process_ou");
        data.templateInfo.template_owner = gr_Template.getValue("process_owner");
      }
      // used for cloning
      data.currentUserId = gs.getUserID();
    }

    function _loadTemplateMap(topParentTask_id) {
        var map = data.map = [];

        // STRY0114416 - 4
        var gr_Task = new GlideRecordSecure('x_153465_discovert_route_tasks');
        if (gr_Task.get(topParentTask_id)) {
            var uiChec = new uiConditionCheck();
            data.canRunTemplate = uiChec.runTemplateUIAction(gr_Task);
            data.title = gr_Task.getValue('short_description');
            // RJ - TUP - STRY0068618 - added run template
            data.templateId = gr_Task.getValue('tasker_process_definition');
            data.templateName = gr_Task.getDisplayValue('tasker_process_definition');
            // STRY0040294 - use record watcher to keep grid synced
            // STRY0091251
            // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode Decimal Codes when entering
            // var templateWidgetData = new TemplateWidgetData();
            // data.fieldsInModel = templateWidgetData.loadTemplateTreeFieldsInModelAndFieldLabels(gr_Task);
            // templateWidgetData.buildTemplateMap('discovertasker-processtemplatetreegraph', map, gr_Task, data.fieldsInModel)
            var taskWidgetData = new TaskWidgetData();
            data.fieldsInModel = taskWidgetData.loadTemplateTreeFieldsInModelAndFieldLabels(gr_Task);
            taskWidgetData.buildTaskMap('discovertasker-processtemplatetreegraph', map, gr_Task, data.fieldsInModel);

            // STRY0113121 - used in all the suspense date warnings
            // DFCT0010725
            data.dateLabel = gr_Task.u_suspense_date.getLabel().toLowerCase();

        }
    }

})($sp, input, data, options, gs);
